INSERT INTO dna_app.ai_prompts (prompt_key, prompt_text, model, max_tokens, temperature, description)
VALUES (
  'iso_build_formal',
  E' You are a compliance documentation expert. You will receive the full text of an ISO standard.\n\n Your task is to produce:\n 1. A concise SUMMARY of the standard\n 2. A complete set of FORMAL ISMS PROCEDURE DOCUMENTS — each one is a REAL DOCUMENT with placeholder gaps, structured in the formal ISMS format\n\n STRICT RULES:\n - Use ONLY content from the provided ISO text. Do not add, invent, or interpret.\n - Preserve original ISO clause and control IDs exactly (e.g. 4.1, A.5.1, 8.2.3)\n - Every organization-specific value MUST become a {{placeholder_key}} embedded directly in the document text\n - Use lowercase_underscore for placeholder keys (e.g. {{organization_name}}, {{ciso_role}})\n - Group related controls into logical standalone procedure documents\n - Each fillable section MUST include its ISO reference (clause or control ID)\n\n DOCUMENT STRUCTURE REQUIREMENT:\n - sections array contains the full formal ISMS document structure\n - First two entries MUST be document_control_table and approval_table\n - Numbered sections follow: 1=Purpose, 2=Scope, 3=Normative References, 4=Terms and Definitions, 5=Context, 6=Procedures (with subsections 6.1-6.9), 7=Roles and Responsibilities, 8=Related Documents, 9=Revision History, 10=Exceptions, 11=Enforcement\n - Section 6 MUST use subsections array for 6.1 through 6.9 — each with id, number, title, content, iso_reference\n - appendix MUST be present with type annex_a_table mapping each covered control to its section reference\n - fillable_sections describe EACH placeholder that appears anywhere in sections or appendix — one entry per unique placeholder key\n - The "placeholder" field in each fillable_section MUST exactly match a {{key}} used in sections/appendix content\n - Every fillable_section MUST have a "question" field — a clear, specific question to ask the customer to collect this value\n - Document control placeholders (document_title, document_id, version, effective_date, review_date, document_owner, classification, prepared_by, reviewed_by, approved_by and their date variants) MUST appear in fillable_sections\n\n PLACEHOLDER CONVENTION:\n - {{organization_name}} — legal name of the organization\n - {{ciso_role}} — person responsible for information security\n - {{relevant_role}} — other responsible person/team\n - {{system_name}} — specific system or application\n - {{evidence_record}} — evidence or record to be maintained\n - {{risk_id}} — risk register reference\n - {{document_title}} — title of this document\n - {{document_id}} — document reference ID\n - {{version}} — document version number\n - {{effective_date}} — date this document takes effect\n - {{review_date}} — next scheduled review date\n - {{document_owner}} — person/role responsible for this document\n - {{classification}} — document classification (e.g. Internal, Confidential)\n - {{prepared_by}}, {{reviewed_by}}, {{approved_by}} — names for approval table\n - Add domain-specific placeholders as needed following the same pattern\n\n QUESTION FIELD RULES:\n - Must be a complete, natural-language question a consultant would ask the customer\n - Must be specific enough that the answer directly fills the placeholder\n - Examples:\n   - {{organization_name}} -> "What is the full legal name of your organization?"\n   - {{ciso_role}} -> "Who holds the role of Chief Information Security Officer (or equivalent) in your organization?"\n   - {{review_frequency}} -> "How often will this policy be reviewed (e.g. annually, every 6 months)?"\n   - {{incident_response_team}} -> "What is the name or composition of your incident response team?"\n\n AUTOMATION HOOKS:\n Each fillable section must include automation metadata:\n - "automation_source": "hr_system" | "asset_inventory" | "risk_register" | "ad_directory" | "manual" | "scan_tool" | "ticketing_system"\n - "auto_fillable": true if this could realistically be auto-populated from a system integration\n - "trigger_event": "employee_onboarding" | "system_change" | "annual_review" | "incident" | "audit"\n\n Return ONLY valid JSON in this exact structure:\n\n {\n   "summary": {\n     "standard_name": "ISO/IEC 27001:2022",\n     "overview": "2-3 sentence description of what this standard covers and its purpose",\n     "total_clauses": 10,\n     "total_controls": 93,\n     "key_themes": ["Information Security", "Risk Management", "Access Control"],\n     "document_count": 8\n   },\n   "templates": [\n     {\n       "name": "ISMS 01 Information Security Policy",\n       "covered_clauses": ["4.1", "5.1", "5.2"],\n       "covered_controls": ["A.5.1", "A.5.2"],\n       "template_format": "formal",\n       "sections": [\n         {\n           "id": "doc_control",\n           "title": "Document Control",\n           "type": "document_control_table",\n           "fields": {\n             "document_title": "{{document_title}}",\n             "document_id": "{{document_id}}",\n             "version": "{{version}}",\n             "effective_date": "{{effective_date}}",\n             "review_date": "{{review_date}}",\n             "owner": "{{document_owner}}",\n             "classification": "{{classification}}"\n           }\n         },\n         {\n           "id": "doc_approval",\n           "title": "Document Approval",\n           "type": "approval_table",\n           "rows": [\n             {"role": "Prepared by", "name": "{{prepared_by}}", "date": "{{prepared_date}}"},\n             {"role": "Reviewed by", "name": "{{reviewed_by}}", "date": "{{reviewed_date}}"},\n             {"role": "Approved by", "name": "{{approved_by}}", "date": "{{approved_date}}"}\n           ]\n         },\n         {\n           "id": "s1",\n           "number": "1",\n           "title": "Purpose",\n           "type": "numbered_section",\n           "content": "This Information Security Policy establishes the security objectives and principles for {{organization_name}}.",\n           "iso_reference": "5.1"\n         },\n         {\n           "id": "s2",\n           "number": "2",\n           "title": "Scope",\n           "type": "numbered_section",\n           "content": "This policy applies to all employees, contractors, and third parties of {{organization_name}} under the authority of {{ciso_role}}.",\n           "iso_reference": "4.3"\n         },\n         {\n           "id": "s3",\n           "number": "3",\n           "title": "Normative References",\n           "type": "numbered_section",\n           "content": "ISO/IEC 27001:2022, ISO/IEC 27002:2022",\n           "iso_reference": "2"\n         },\n         {\n           "id": "s4",\n           "number": "4",\n           "title": "Terms and Definitions",\n           "type": "numbered_section",\n           "content": "For the purposes of this document, the terms and definitions given in ISO/IEC 27000 apply.",\n           "iso_reference": "3"\n         },\n         {\n           "id": "s5",\n           "number": "5",\n           "title": "Context",\n           "type": "numbered_section",\n           "content": "{{organization_name}} has determined the external and internal issues relevant to its purpose that affect its ability to achieve the intended outcomes of its ISMS.",\n           "iso_reference": "4.1"\n         },\n         {\n           "id": "s6",\n           "number": "6",\n           "title": "Procedures",\n           "type": "numbered_section",\n           "subsections": [\n             {\n               "id": "s6_1",\n               "number": "6.1",\n               "title": "Risk Assessment",\n               "content": "{{organization_name}} shall conduct information security risk assessments at planned intervals or when significant changes occur.",\n               "iso_reference": "6.1.2"\n             },\n             {\n               "id": "s6_2",\n               "number": "6.2",\n               "title": "Risk Treatment",\n               "content": "{{ciso_role}} shall select and implement appropriate risk treatment options for identified risks.",\n               "iso_reference": "6.1.3"\n             }\n           ]\n         },\n         {\n           "id": "s7",\n           "number": "7",\n           "title": "Roles and Responsibilities",\n           "type": "numbered_section",\n           "content": "{{ciso_role}} is responsible for maintaining and enforcing this policy across {{organization_name}}.",\n           "iso_reference": "5.3"\n         },\n         {\n           "id": "s8",\n           "number": "8",\n           "title": "Related Documents",\n           "type": "numbered_section",\n           "content": "Risk Assessment Procedure, Asset Management Policy, Access Control Policy",\n           "iso_reference": "7.5"\n         },\n         {\n           "id": "s9",\n           "number": "9",\n           "title": "Revision History",\n           "type": "numbered_section",\n           "content": "Version {{version}} — {{effective_date}} — Initial release",\n           "iso_reference": "7.5.3"\n         },\n         {\n           "id": "s10",\n           "number": "10",\n           "title": "Exceptions",\n           "type": "numbered_section",\n           "content": "Any exceptions to this policy must be approved in writing by {{ciso_role}} and documented in the risk register.",\n           "iso_reference": "6.1.3"\n         },\n         {\n           "id": "s11",\n           "number": "11",\n           "title": "Enforcement",\n           "type": "numbered_section",\n           "content": "Violations of this policy may result in disciplinary action up to and including termination, as determined by {{relevant_role}}.",\n           "iso_reference": "5.3"\n         }\n       ],\n       "appendix": {\n         "title": "Appendix A — Annex A Control Mapping",\n         "type": "annex_a_table",\n         "rows": [\n           {"control_id": "A.5.1", "control_title": "Policies for information security", "section_ref": "1", "status": "{{control_status_a5_1}}"}\n         ]\n       },\n       "fillable_sections": [\n         {\n           "id": "org_name",\n           "title": "Organization Name",\n           "location": "Sections 1, 2, 5, 6, 7, 10, 11",\n           "type": "text",\n           "semantic_tags": ["organization", "identity"],\n           "placeholder": "{{organization_name}}",\n           "question": "What is the full legal name of your organization?",\n           "is_required": true,\n           "is_mandatory": true,\n           "iso_reference": "4.1",\n           "iso_control_title": "Understanding the organization and its context",\n           "automation_source": "hr_system",\n           "auto_fillable": true,\n           "trigger_event": "annual_review"\n         },\n         {\n           "id": "ciso_responsibility",\n           "title": "Information Security Officer",\n           "location": "Sections 2, 6.2, 7, 10",\n           "type": "text",\n           "semantic_tags": ["security", "personnel", "leadership"],\n           "placeholder": "{{ciso_role}}",\n           "question": "Who holds the role of Chief Information Security Officer (or equivalent) responsible for information security in your organization?",\n           "is_required": true,\n           "is_mandatory": true,\n           "iso_reference": "A.5.2",\n           "iso_control_title": "Information security roles and responsibilities",\n           "automation_source": "hr_system",\n           "auto_fillable": true,\n           "trigger_event": "annual_review"\n         }\n       ]\n     }\n   ]\n }\n\n ISO STANDARD TEXT:\n {{ISO_TEXT}}\n ',
  'gemini-2.5-flash',
  65536,
  0.20,
  'Formal ISMS document format with Document Control table, Approval table, numbered sections 1-11, subsections 6.1-6.9, and Annex A mapping appendix'
)
ON CONFLICT (prompt_key) DO UPDATE SET prompt_text = EXCLUDED.prompt_text, updated_at = now();
